function asObject(value, fallback = {}) {
  if (!value) return fallback;

  if (typeof value === "object" && !Array.isArray(value)) {
    return value;
  }

  if (typeof value === "string") {
    try {
      const parsed = JSON.parse(value);
      return parsed && typeof parsed === "object" ? parsed : fallback;
    } catch {
      return fallback;
    }
  }

  return fallback;
}

const input = $json;

const decision = asObject(input.decision);
const contextPacket = asObject(input.context_packet);
const event = asObject(input.event);
const lead = asObject(input.lead);
const leadState = asObject(input.lead_state);
const meta = asObject(input.meta);

if (!decision.action) {
  throw new Error("Missing decision.action");
}

if (!contextPacket || Object.keys(contextPacket).length === 0) {
  throw new Error("Missing context_packet");
}

return [
  {
    json: {
      ...input,

      event,
      lead,
      lead_state: leadState,
      decision,
      context_packet: contextPacket,

      execution_meta: {
        ...(input.execution_meta || {}),
        execution_id:
          input.execution_meta?.execution_id ||
          Date.now().toString(),
        timestamp: new Date().toISOString(),
        source: "6_action_executor"
      },

      meta: {
        ...meta,
        received_by: "6_action_executor",
        original_action: decision.action
      }
    }
  }
];

const globalAllowedActions = [
  // Flujo base
  "ask_missing_data",
  "send_quote",
  "answer_question",
  "answer_objection",
  "offer_booking",
  "offer_available_slots",
  "confirm_booking",
  "schedule_followup",
  "handoff_human",

  // Prioridad 2 â€” flujo comercial completo
  "cancel_booking",
  "reschedule_booking",
  "collect_address",
  "confirm_address",
  "send_pre_service_instructions",
  "notify_on_the_way",
  "request_review",
  "request_referral",
  "send_service_menu",
  "recommend_service"
];

let action = $json.decision?.action;
const contextAllowedActions = $json.context_packet?.allowed_actions;
const errors = [];
function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function isFilled(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === "string" && value.trim() === "") return false;
  return true;
}

function asksRecommendation(rawText) {
  const t = normalizeText(rawText);

  return (
    t.includes("que me recomiendas") ||
    t.includes("que recomiendas") ||
    t.includes("cual me recomiendas") ||
    t.includes("cual me conviene") ||
    t.includes("no se cual elegir") ||
    t.includes("no se que servicio") ||
    t.includes("ayudame a elegir") ||
    t.includes("recomiendame")
  );
}

const state = $json.context_packet?.state || {};
const latestUserMessage = $json.context_packet?.conversation?.latest_user_message || "";

const hasCommercialContext =
  isFilled(state.service_interest) &&
  isFilled(state.vehicle_type) &&
  isFilled(state.district);

if (
  action === "recommend_service" &&
  hasCommercialContext &&
  !asksRecommendation(latestUserMessage) &&
  Array.isArray(contextAllowedActions) &&
  contextAllowedActions.includes("send_quote")
) {
  action = "send_quote";

  $json.decision = {
    ...($json.decision || {}),
    action: "send_quote",
    reason: "action_executor_guard_forced_send_quote_because_service_vehicle_district_are_complete",
    message: "",
    state_update: {
      ...($json.decision?.state_update || {}),
      service_interest: state.service_interest,
      vehicle_type: state.vehicle_type,
      district: state.district,
      stage: "qualified",
      next_goal: "send_quote",
      last_bot_action: "send_quote_in_progress",
      missing_fields: []
    }
  };
}

if (!action) {
  errors.push("Missing action");
}

if (action && !globalAllowedActions.includes(action)) {
  errors.push(`Unsupported action: ${action}`);
}

if (!Array.isArray(contextAllowedActions) || contextAllowedActions.length === 0) {
  errors.push("Missing or empty context_packet.allowed_actions");
}

if (
  action &&
  Array.isArray(contextAllowedActions) &&
  contextAllowedActions.length > 0 &&
  !contextAllowedActions.includes(action)
) {
  errors.push(
    `Action not allowed in current state: ${action}. Allowed: ${contextAllowedActions.join(", ")}`
  );
}

if (errors.length > 0) {
  return [{
    error: true,
    errors,
    original: $json
  }];
}

return [{
  ...$json,
  validation: {
    global_action_valid: true,
    context_action_valid: true,
    allowed_actions_checked: contextAllowedActions
  }
}];

const validationMissing = Array.isArray($json.validation?.missing_fields)
  ? $json.validation.missing_fields
  : [];

const decisionMissing = Array.isArray($json.execution_context?.state_update?.missing_fields)
  ? $json.execution_context.state_update.missing_fields
  : [];

const fallbackMissing = Array.isArray($json.state_update?.missing_fields)
  ? $json.state_update.missing_fields
  : [];

const missingFields =
  validationMissing.length > 0
    ? validationMissing
    : decisionMissing.length > 0
      ? decisionMissing
      : fallbackMissing;

return [
  {
    ...$json,
    message_to_send: $json.execution_context.message,
    db_operations: ["messages", "lead_state"],
    state_update: {
      ...($json.execution_context.state_update || {}),
      missing_fields: missingFields,
      last_bot_action: "ask_missing_data",
    },
  },
];

return [
  {
    ...$json,
    db_operations: ["messages", "offers_or_quotes"],

    state_update: {
      ...($json.execution_context.state_update || {}),
      missing_fields: []
    },

    internal_status: "send_quote_in_progress"
  }
];

return [{
  ...$json,
  message_to_send: $json.execution_context.message,
  db_operations: ["messages", "lead_state"],
  state_update: {
    ...($json.execution_context.state_update || {}),
    last_bot_action: "answer_question",
    missing_fields: Array.isArray($json.execution_context.state_update?.missing_fields)
      ? $json.execution_context.state_update.missing_fields
      : []
  }
}];

return [{
  ...$json,
  message_to_send: $json.execution_context.message,
  db_operations: ["messages"],
  state_update: {
    ...$json.execution_context.state_update,
    stage: "closing",
    next_goal: "book_appointment",
    last_bot_action: "offer_booking"
  }
}];

const data = $json;
const ctx = data.execution_context || {};

const payloadObject = {
  ...data,
  db_operations: ["appointments", "messages", "lead_state"],
  booking_request: {
    lead_id: ctx.lead_id,
    channel: ctx.channel,
    service_interest: ctx.service_interest,
    vehicle_type: ctx.vehicle_type,
    district: ctx.district,
    booking_date: ctx.booking_date,
    booking_time: ctx.booking_time,
    slot_id: ctx.slot_id,
    availability_confirmed: ctx.availability_confirmed,
    duration_minutes: ctx.duration_minutes || 120,
    calendar_id: ctx.calendar_id || "primary",
    service_address: ctx.service_address || ctx.address || null,
    address_reference: ctx.address_reference || null,
    address_confirmed: ctx.address_confirmed === true
  },
  state_update: {
    ...(ctx.state_update || {}),
    last_bot_action: "confirm_booking_in_progress"
  }
};

return [{
  ...payloadObject,
  payload: JSON.stringify(payloadObject)
}];

return [{
  ...$json,
  db_operations: ["followups"],
  followup: {
    type: $json.execution_context.followup_type,
    scheduled_for: $json.execution_context.scheduled_for
  },
  state_update: {
    ...$json.execution_context.state_update,
    last_bot_action: "schedule_followup"
  }
}];

return [{
  ...$json,
  message_to_send: $json.execution_context.message || "Te voy a derivar con una persona para ayudarte mejor.",
  db_operations: ["handoff_cases", "messages", "lead_state"],
  handoff_case: {
    lead_id: $json.execution_context.lead_id,
    reason: $json.execution_context.handoff_reason || "handoff requested",
    summary:
      $json.execution_context.handoff_summary ||
      $json.context_packet?.conversation?.latest_user_message ||
      "Sin resumen",
    lead: $json.context_packet?.lead || {},
    state: $json.context_packet?.state || {},
    conversation: $json.context_packet?.conversation || {},
    metadata: {
      source_action: "handoff_human",
      idempotency_key: $json.execution_context?.idempotency_key || null
    }
  },
  state_update: {
    ...($json.execution_context.state_update || {}),
    stage: "human_handoff",
    human_handoff: true,
    next_goal: "human_takeover",
    last_bot_action: "handoff_human",
    missing_fields: []
  }
}];

const result = $json;

return [{
  ...result,
  action:
    $json.action ??
    $json.decision?.action ??
    $json.execution_context?.action ??
    "schedule_followup",
  persisted: true,
  records: result.db_operations || result.records || [],
  state_updated: !!result.lead_state_update || !!result.state_update,
  message_sent: result.message_sent === true,
}];

const action =
  $json.execution_context?.action ||
  $json.decision?.action ||
  $json.action ||
  null;
const outcome =
  $json.outcome ||
  $json.execution_result?.outcome ||
  $json.meta?.outcome ||
  null;

const lastBotAction =
  $json.state_update?.last_bot_action ||
  $json.lead_state_update?.last_bot_action ||
  $json.execution_result?.last_bot_action ||
  null;

const bot =
  $json.message ||
  $json.message_to_send ||
  $json.meta?.bot ||
  null;

const messageSent = $json.message_sent === true;

const audit = {
  audit_id: $json.audit_id || null,
  flow_name: $json.flow_name || "action_executor",
  decision: $json.audit_decision || $json.decision || null,
  idempotency_key:
    $json.idempotency_key ||
    $json.execution_context?.idempotency_key ||
    null,
  inbound_message_id:
    $json.inbound_message_id ||
    $json.execution_context?.inbound_message_id ||
    null,
  outbound_message_id:
    $json.outbound_message_id ||
    null
};

const qaFailedReasons = [];

if (!bot) qaFailedReasons.push("bot_null");
if (messageSent !== true) qaFailedReasons.push("message_sent_not_true");
if (!audit.flow_name) qaFailedReasons.push("flow_name_null");
if (!audit.decision) qaFailedReasons.push("decision_null");
if (!audit.idempotency_key) qaFailedReasons.push("idempotency_key_null");
if (!audit.audit_id && $json.message_sent === true) {
  qaFailedReasons.push("audit_not_inserted");
}

if (!audit.inbound_message_id) {
  qaFailedReasons.push("inbound_message_id_null");
}

if (!audit.outbound_message_id && $json.outbound_message_saved === true) {
  qaFailedReasons.push("audit_outbound_message_id_null");
}
if ($json.outbound_message_saved !== true && bot) {
  qaFailedReasons.push("outbound_message_not_saved");
}
const isHandoff = action === "handoff_human";

const handoffResult = {
  human_handoff:
    $json.state_update?.human_handoff === true ||
    $json.lead_state_update?.human_handoff === true ||
    $json.handoff === true,

  handoff_case_id:
    $json.handoff_case_id ||
    $json.meta?.handoff?.handoff_case_id ||
    null,

  assigned_to:
    $json.assigned_to ||
    $json.meta?.handoff?.assigned_to ||
    null,

  assigned_team:
    $json.assigned_team ||
    $json.meta?.handoff?.assigned_team ||
    null,

  notification_sent:
    $json.notification_sent === true ||
    $json.meta?.handoff?.notification_sent === true
};

if (isHandoff) {
  if (handoffResult.human_handoff !== true) {
    qaFailedReasons.push("handoff_human_not_true");
  }

  if (!handoffResult.handoff_case_id) {
    qaFailedReasons.push("handoff_case_id_null");
  }

  if (!handoffResult.assigned_to) {
    qaFailedReasons.push("assigned_to_null");
  }

  if (!handoffResult.assigned_team) {
    qaFailedReasons.push("assigned_team_null");
  }

  if (handoffResult.notification_sent !== true) {
    qaFailedReasons.push("notification_sent_not_true");
  }
}
const proposedStateUpdate =
  $json.proposed_state_update ||
  $json.decision?.state_update ||
  {};
const sanitizedStateUpdate =
  $json.sanitized_state_update ||
  $json.state_update ||
  {};

function normalizeCompareValue(value) {
  if (value === undefined) return "__undefined__";
  if (value === null) return null;

  if (typeof value === "string") {
    const trimmed = value.trim();
    return trimmed === "" ? null : trimmed;
  }

  if (Array.isArray(value)) {
    return JSON.stringify(value);
  }

  if (typeof value === "boolean") {
    return value;
  }

  return value;
}

function valuesMatch(expected, actual) {
  const e = normalizeCompareValue(expected);
  const a = normalizeCompareValue(actual);

  if (e === "__undefined__") return true;

  if (typeof e === "boolean") {
    return a === e || String(a).toLowerCase() === String(e);
  }

  return JSON.stringify(e) === JSON.stringify(a);
}

const persistedStateCurrent =
  $json.persisted_state_current ||
  $json.state?.current ||
  null;

const stateMismatchFields = [];



if ($json.state_updated === true && persistedStateCurrent) {
  const keysToCompare = [
    "stage",
    "intent_last",
    "service_interest",
    "vehicle_type",
    "district",

    "mentioned_vehicle_type",
    "confirmed_vehicle_type",
    "mentioned_district",
    "confirmed_district",

    "last_bot_action",
    "next_goal",
    "human_handoff",
    "booking_date",
    "booking_time",
    "slot_id",
    "availability_confirmed",
    "service_address",
    "address_reference",
    "address_confirmed",
    "cancellation_reason",
    "reschedule_reason",
    "last_appointment_event_id"
  ];

  for (const key of keysToCompare) {
    if (sanitizedStateUpdate[key] === undefined) continue;

  if (!valuesMatch(sanitizedStateUpdate[key], persistedStateCurrent[key])) {
  stateMismatchFields.push({
    field: key,
    expected: sanitizedStateUpdate[key],
    actual: persistedStateCurrent[key],
  });
}
}
}

if (stateMismatchFields.length > 0) {
  qaFailedReasons.push(
    "state_current_does_not_match_sanitized_state_update:" +
    JSON.stringify(stateMismatchFields)
  );
}
if ($json.state_updated === true && !persistedStateCurrent) {
  qaFailedReasons.push("state_current_missing_after_update");
}

return [{
  execution_result: {
    success: qaFailedReasons.length === 0,
    action,
    outcome,
    last_bot_action: lastBotAction,
    bot,
    message_sent: messageSent,
    message_saved: $json.outbound_message_saved === true,
    outbound_message_id: $json.outbound_message_id || null,
    state_updated: $json.state_updated === true,
    state: {
  proposed_update: proposedStateUpdate,
  sanitized_update: sanitizedStateUpdate,
  current: persistedStateCurrent,
  mismatch_fields: stateMismatchFields,
},

    handoff: isHandoff ? handoffResult : null,

    audit,
    qa: {
      passed: qaFailedReasons.length === 0,
      failed_reasons: qaFailedReasons
    },
    db_records_created: $json.records || $json.db_operations || [],
    notes: $json.notes || []
  }
}];

const msg = (
  $json.execution_context?.message ||
  $json.decision?.message ||
  ""
).trim();

const isWillThink = (() => {
  const t = String($json.context_packet?.conversation?.latest_user_message || "").toLowerCase();
  return t.includes("lo voy a pensar") || t.includes("lo pensare") || t.includes("lo pensar") || t.includes("despues veo") || t.includes("después veo");
})();

const fallback = isWillThink
  ? "Perfecto, tómate tu tiempo. Cualquier cosa me dices y te ayudo feliz. Si te parece, puedo enviarte los horarios disponibles o agendar cuando te acomode. ¿Qué prefieres?"
  : "Perfecto. Cualquier cosa me dices y te ayudo feliz. ¿Qué te gustaría revisar?";

return [
  {
    json: {
      ...$json,
      message_to_send: msg || fallback,
      db_operations: ["messages", "lead_state"],
      state_update: {
        ...($json.execution_context?.state_update || {}),
        stage: "closing",
        intent_last: "objection_answered",
        next_goal: "book_appointment",
        last_bot_action: "answer_objection",
        missing_fields: []
      }
    }
  }
];

const original = $json.original || $json;

const decision =
  original.decision ||
  original.original?.decision ||
  null;

const contextPacket =
  original.context_packet ||
  original.original?.context_packet ||
  {};

const leadId =
  original.execution_context?.lead_id ||
  contextPacket.lead?.id ||
  original.lead?.id ||
  null;

const channel =
  original.execution_context?.channel ||
  contextPacket.lead?.channel ||
  original.event?.channel ||
  "whatsapp";

const action =
  original.execution_context?.action ||
  decision?.action ||
  null;

const inboundMessageId =
  original.execution_context?.inbound_message_id ||
  contextPacket.conversation?.last_message_id ||
  original.event?.message_id ||
  null;

const idempotencyKey =
  original.execution_context?.idempotency_key ||
  (
    leadId && inboundMessageId && action
      ? `${leadId}__${inboundMessageId}__${action}`
      : null
  );

return [
  {
    json: {
      ...original,

      error: true,
      errors: $json.errors || original.errors || ["validation error"],

      decision,
      context_packet: contextPacket,

      lead_id: leadId,
      channel,
      idempotency_key: idempotencyKey,

      execution_context: {
        ...(original.execution_context || {}),
        lead_id: leadId,
        channel,
        action,
        inbound_message_id: inboundMessageId,
        idempotency_key: idempotencyKey
      },

      message_sent: false,
      outbound_message_saved: false,
      state_updated: false,

      execution_result: {
        success: false,
        action,
        message_sent: false,
        state_updated: false,
        db_records_created: [],
        notes: $json.errors || original.errors || ["validation error"]
      },

      notes: [
        ...(original.notes || []),
        "action_executor_validation_error"
      ]
    }
  }
];

const originalInput = $("IN LLM_Descision").first().json;

const originalContext = originalInput.context_packet || {};
const currentContext = $json.context_packet || originalContext || {};

const leadId =
  $json.execution_context?.lead_id ||
  $json.lead_id ||
  currentContext.lead?.id ||
  originalContext.lead?.id ||
  null;

const phone =
  currentContext.lead?.phone ||
  $json.execution_context?.phone ||
  $json.phone ||
  originalContext.lead?.phone ||
  null;

const channel =
  $json.execution_context?.channel ||
  $json.channel ||
  currentContext.lead?.channel ||
  originalContext.lead?.channel ||
  "whatsapp";

const chatSessionId =
  $json.execution_context?.chat_session_id ||
  $json.chat_session_id ||
  currentContext.conversation?.chat_session_id ||
  currentContext.source_metadata?.chat_session_id ||
  currentContext.event?.source_metadata?.chat_session_id ||
  originalContext.conversation?.chat_session_id ||
  originalContext.source_metadata?.chat_session_id ||
  originalContext.event?.source_metadata?.chat_session_id ||
  null;

if (!leadId) {
  throw new Error("Missing lead_id for outbound message");
}

if (!phone) {
  throw new Error("Missing phone for outbound message");
}

return [{
  ...$json,

  lead_id: leadId,
  phone,
  channel,
  chat_session_id: chatSessionId,

  message: $json.message_to_send || $json.message || "",
  message_type: $json.message_type || "text",

  context_packet: currentContext,

  execution_context: {
    ...($json.execution_context || {}),
    lead_id: leadId,
    phone,
    channel,
    chat_session_id: chatSessionId,
    action:
      $json.execution_context?.action ||
      originalInput.decision?.action ||
      null
  },

  state_update: $json.state_update || {},
  db_operations: $json.db_operations || [],

  quote: $json.quote || null,
  appointment: $json.appointment || null,
  followup: $json.followup || null,

  quote_db_id: $json.quote_was_created === true ? ($json.quote_db_id || null) : null,
quote_was_created: $json.quote_was_created === true
}];

return [{
  execution_result: {
    success: true,
    action: $json.execution_context?.action || $json.decision?.action || null,
    message_sent: false,
    state_updated: false,
    db_records_created: [],
    notes: ["skipped due to idempotency"]
  }
}];

const originalInput = $("IN LLM_Descision").first().json;

const originalContext = originalInput.context_packet || {};
const current = $json.context_packet?.state || originalContext.state || {};
const patch =
  $json.sanitized_state_update ||
  $json.state_update ||
  {};

const leadId =
  $json.execution_context?.lead_id ||
  $json.lead_id ||
  $json.context_packet?.lead?.id ||
  originalContext.lead?.id ||
  null;

const phone =
  $json.execution_context?.phone ||
  $json.phone ||
  $json.context_packet?.lead?.phone ||
  originalContext.lead?.phone ||
  null;

const channel =
  $json.execution_context?.channel ||
  $json.channel ||
  $json.context_packet?.lead?.channel ||
  originalContext.lead?.channel ||
  "whatsapp";

if (!leadId) {
  throw new Error("Missing lead_id in build_state_payload");
}

// eliminar solo undefined, no null
const cleanPatch = Object.fromEntries(
  Object.entries(patch).filter(([_, value]) => value !== undefined)
);
if (cleanPatch.confirmed_vehicle_type === undefined && cleanPatch.vehicle_type) {
  cleanPatch.confirmed_vehicle_type = cleanPatch.vehicle_type;
}

if (cleanPatch.confirmed_district === undefined && cleanPatch.district) {
  cleanPatch.confirmed_district = cleanPatch.district;
}

let lead_state_update = {
  ...current,
  ...cleanPatch,
  updated_at: new Date().toISOString()
};

// asegurar que missing_fields sea array internamente
if (!Array.isArray(lead_state_update.missing_fields)) {
  lead_state_update.missing_fields = Array.isArray(current.missing_fields)
    ? current.missing_fields
    : [];
}

return [{
  ...$json,

  lead_id: leadId,
  phone,
  channel,

  context_packet: $json.context_packet || originalContext,

  execution_context: {
    ...($json.execution_context || {}),
    lead_id: leadId,
    phone,
    channel,
    action:
      $json.execution_context?.action ||
      originalInput.decision?.action ||
      null
  },

  lead_state_update
}];

const originalInput = $("IN LLM_Descision").first().json;

const contextPacket =
  $json.context_packet ||
  originalInput.context_packet ||
  {};

const decision =
  $json.decision ||
  originalInput.decision ||
  null;

const executionContext = {
  ...($json.execution_context || {})
};

const leadId =
  executionContext.lead_id ||
  $json.lead_id ||
  contextPacket.lead?.id ||
  null;

const channel =
  executionContext.channel ||
  $json.channel ||
  contextPacket.lead?.channel ||
  "whatsapp";

const action =
  executionContext.action ||
  decision?.action ||
  $json.action ||
  null;

const inboundMessageId =
  executionContext.inbound_message_id ||
  contextPacket.conversation?.last_message_id ||
  contextPacket.event?.message_id ||
  originalInput.event?.message_id ||
  null;

const idempotencyKey =
  executionContext.idempotency_key ||
  $json.idempotency_key ||
  (
    leadId && inboundMessageId && action
