  last_appointment_event_id: $json.last_appointment_event_id || null,

  updated_at: $json.updated_at || null,
};

return [{
  ...$json,
  state_updated: !!persistedState.updated_at,
  persisted_state_current: persistedState,
  state: {
    current: persistedState,
